const body = $input.first().json.body || $input.first().json;

// JST変換
const dt = new Date(body.timestamp || new Date().toISOString());
const jst = new Date(dt.getTime() + 9 * 60 * 60 * 1000);
const pad = n => String(n).padStart(2,'0');
const jstStr = `${jst.getUTCFullYear()}/${pad(jst.getUTCMonth()+1)}/${pad(jst.getUTCDate())} ${pad(jst.getUTCHours())}:${pad(jst.getUTCMinutes())}`;

const c = body.contact || {};
const d = body.diagnosis || {};
const ops = d.operationAnswers || {};
const opts = d.options || {};
const r = body.result || {};

// 社内メール本文
const mailBodyInternal = `お問い合わせ済みのお客様から、かんたんプラン診断の回答がありました。

━━━━━━━━━━━━━━
【お客様情報】
━━━━━━━━━━━━━━
姓　　　：${c.lastName || ''}
名　　　：${c.firstName || ''}
メール　：${c.email || ''}
送信日時：${jstStr}
※お客様にも同内容のメールを送信済みです。

━━━━━━━━━━━━━━
【診断回答内容】
━━━━━━━━━━━━━━
${body.summaryText || ''}

---
本メールはn8n自動送信です。`;

// お客様メール本文
const recOpts = (r.recommendedOptions || []).length > 0 ? r.recommendedOptions.join('、') : '追加サポートなし';
const initialFeeStr = (r.initialFee || 0).toLocaleString();
const monthlyFeeStr = (r.monthlyFee || 0).toLocaleString();
const mailBodyCustomer = `${c.lastName || ''} ${c.firstName || ''} 様

このたびは、民泊管理バンクの「かんたんプラン診断」をご活用いただき、誠にありがとうございます。
診断結果をご案内いたします。

━━━━━━━━━━━━━━
【診断結果】
━━━━━━━━━━━━━━

■ おすすめプラン
　${r.planName || ''}

■ 概算お見積り（税抜）
　初期費用：${initialFeeStr}円
　月額費用：${monthlyFeeStr}円

■ おすすめのサポート
　${recOpts}

━━━━━━━━━━━━━━
【診断でご選択いただいた内容】
━━━━━━━━━━━━━━
${body.summaryText || ''}

━━━━━━━━━━━━━━

※ 本診断の結果・概算金額はあくまで目安です。
※ 表示金額はすべて税抜・1物件あたりです。別途、Beds24・PriceLabs等の実費が発生します。

診断結果は弊社担当者にも共有されているため、
担当者よりあらためてご連絡させていただきます。
ご不明点がございましたら、本メールに返信いただくか、下記までお気軽にお問い合わせください。

今後ともよろしくお願いいたします。

────────────────────
民泊管理バンク
consulter@bizpato.com
────────────────────`;

return [{
  json: {
    jstStr,
    lastName: c.lastName || '',
    firstName: c.firstName || '',
    email: c.email || '',
    formType: d.formType || '',
    checkinNeeded: d.checkinNeeded || '',
    guest: ops.guest || '',
    cleaning: ops.cleaning || '',
    review: ops.review || '',
    location: d.location || '',
    opt_setup: opts['初期セットアップ'] || '',
    opt_booking: opts['予約サイトへの掲載'] || '',
    opt_system: opts['予約システムの連携設定'] || '',
    opt_manual: opts['ハウスマニュアルの作成'] || '',
    opt_photo: opts['物件写真の撮影'] || '',
    opt_evacuation: opts['避難経路図の作成'] || '',
    opt_price: opts['宿泊料金の調整'] || '',
    opt_identity: opts['ゲストの本人確認'] || '',
    planName: r.planName || '',
    initialFee: r.initialFee || '',
    monthlyFee: r.monthlyFee || '',
    recommendedOptions: (r.recommendedOptions || []).join(', '),
    kubun: 'フォロー',
    mailSubjectInternal: `【かんたんプラン診断・フォロー】診断結果 - ${c.lastName || ''} ${c.firstName || ''} 様`,
    mailBodyInternal,
    mailSubjectCustomer: '【民泊管理バンク】かんたんプラン診断の結果のご案内',
    mailBodyCustomer
  }
}];
